#include <stdio.h>
#include <stdlib.h>

int cmp(const void *x, const void *y) {
    return *(int *)x - *(int *)y;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, D;
        scanf("%d %d", &N, &D);
        int a[105];
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        qsort(a, N, sizeof(int), cmp);
        long long dp[105] = {0};
        for (int i = 2; i <= N; ++i) {
            dp[i] = dp[i-1];
            if (a[i-1] - a[i-2] < D) {
                long long cand = dp[i-2] + a[i-1] + a[i-2];
                if (cand > dp[i]) dp[i] = cand;
            }
        }
        printf("%lld\n", dp[N]);
    }
    return 0;
}

