import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); D = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        a.sort()
        dp = [0]*(N+1)
        for i in range(2, N+1):
            dp[i] = dp[i-1]
            if a[i-1] - a[i-2] < D:
                cand = dp[i-2] + a[i-1] + a[i-2]
                if cand > dp[i]:
                    dp[i] = cand
        out.append(str(dp[N]))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

